import{_ as a,o as e,c as l,a2 as r}from"./chunks/framework.BQ1gajhD.js";const q=JSON.parse('{"title":"中山公园","description":"","frontmatter":{},"headers":[],"relativePath":"parks/zhongshan-park.md","filePath":"parks/zhongshan-park.md","lastUpdated":1784712887000}'),o={name:"parks/zhongshan-park.md"};function n(i,t,d,h,s,g){return e(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="中山公园" tabindex="-1">中山公园 <a class="header-anchor" href="#中山公园" aria-label="Permalink to &quot;中山公园&quot;">​</a></h1><blockquote><p>&quot;明清社稷坛，北京郁金香名园。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>中山公园位于北京市中心，天安门西侧，是明清两代皇帝祭祀土地神和五谷神的地方。公园始建于明永乐十八年（1420年），原称&quot;社稷坛&quot;。1928年，为纪念孙中山先生，改名&quot;中山公园&quot;。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">6:00-21:00（旺季），6:30-20:00（淡季）</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">3元</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">2-3小时</td></tr><tr><td style="text-align:left;"><strong>最佳季节</strong></td><td style="text-align:left;">春季郁金香，秋季菊花</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁1号线天安门西站</td></tr><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市东城区中华路4号</td></tr></tbody></table><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><h3 id="社稷坛" tabindex="-1">社稷坛 <a class="header-anchor" href="#社稷坛" aria-label="Permalink to &quot;社稷坛&quot;">​</a></h3><p>明永乐十八年（1420年），明成祖朱棣按照&quot;左祖右社&quot;的制度，在天安门西侧修建社稷坛，祭祀土地神和五谷神。</p><p>社稷坛是皇帝祭祀土地神和五谷神的地方，&quot;社&quot;为土地神，&quot;稷&quot;为五谷神。</p><h3 id="民国改名" tabindex="-1">民国改名 <a class="header-anchor" href="#民国改名" aria-label="Permalink to &quot;民国改名&quot;">​</a></h3><p>1928年，为纪念孙中山先生，社稷坛改名&quot;中山公园&quot;。</p><h3 id="现代发展" tabindex="-1">现代发展 <a class="header-anchor" href="#现代发展" aria-label="Permalink to &quot;现代发展&quot;">​</a></h3><p>新中国成立后，中山公园多次修缮扩建，增加了花卉展览等设施。</p><h2 id="建筑特色" tabindex="-1">建筑特色 <a class="header-anchor" href="#建筑特色" aria-label="Permalink to &quot;建筑特色&quot;">​</a></h2><h3 id="社稷坛-1" tabindex="-1">社稷坛 <a class="header-anchor" href="#社稷坛-1" aria-label="Permalink to &quot;社稷坛&quot;">​</a></h3><p>社稷坛是中山公园的核心建筑，是明清皇帝祭祀土地神和五谷神的地方。</p><h4 id="布局" tabindex="-1">布局 <a class="header-anchor" href="#布局" aria-label="Permalink to &quot;布局&quot;">​</a></h4><ul><li><strong>坛台</strong>：方形，三层，五色土</li><li><strong>坛墙</strong>：四面，按方位涂色</li><li><strong>戟门</strong>：坛南的正门</li></ul><h4 id="五色土" tabindex="-1">五色土 <a class="header-anchor" href="#五色土" aria-label="Permalink to &quot;五色土&quot;">​</a></h4><p>社稷坛上铺设五色土，象征&quot;普天之下，莫非王土&quot;：</p><ul><li><strong>东方青土</strong>：东方属木，色青</li><li><strong>南方红土</strong>：南方属火，色红</li><li><strong>西方白土</strong>：西方属金，色白</li><li><strong>北方黑土</strong>：北方属水，色黑</li><li><strong>中央黄土</strong>：中央属土，色黄</li></ul><h3 id="拜殿-中山堂" tabindex="-1">拜殿（中山堂） <a class="header-anchor" href="#拜殿-中山堂" aria-label="Permalink to &quot;拜殿（中山堂）&quot;">​</a></h3><p>拜殿位于社稷坛北，是皇帝祭祀时休息的地方。现为&quot;中山堂&quot;，用于举办展览。</p><h3 id="保卫和平坊" tabindex="-1">保卫和平坊 <a class="header-anchor" href="#保卫和平坊" aria-label="Permalink to &quot;保卫和平坊&quot;">​</a></h3><p>保卫和平坊是中山公园的标志性建筑，原称&quot;克林德碑&quot;，建于1901年。1952年，改名为&quot;保卫和平坊&quot;。</p><h3 id="兰亭八柱亭" tabindex="-1">兰亭八柱亭 <a class="header-anchor" href="#兰亭八柱亭" aria-label="Permalink to &quot;兰亭八柱亭&quot;">​</a></h3><p>亭内有兰亭碑，刻有王羲之的《兰亭集序》和乾隆皇帝的题诗。</p><h3 id="古柏" tabindex="-1">古柏 <a class="header-anchor" href="#古柏" aria-label="Permalink to &quot;古柏&quot;">​</a></h3><p>中山公园内有大量的古柏，是明永乐年间种植的，已有600余年历史。</p><h2 id="花卉展览" tabindex="-1">花卉展览 <a class="header-anchor" href="#花卉展览" aria-label="Permalink to &quot;花卉展览&quot;">​</a></h2><h3 id="郁金香展" tabindex="-1">郁金香展 <a class="header-anchor" href="#郁金香展" aria-label="Permalink to &quot;郁金香展&quot;">​</a></h3><p>中山公园是北京最著名的郁金香观赏地，每年春季举办郁金香展。</p><h4 id="展览时间" tabindex="-1">展览时间 <a class="header-anchor" href="#展览时间" aria-label="Permalink to &quot;展览时间&quot;">​</a></h4><p>每年4月中旬至5月上旬。</p><h4 id="观赏地点" tabindex="-1">观赏地点 <a class="header-anchor" href="#观赏地点" aria-label="Permalink to &quot;观赏地点&quot;">​</a></h4><p>主要分布在社稷坛周围、南坛门等地。</p><h4 id="品种" tabindex="-1">品种 <a class="header-anchor" href="#品种" aria-label="Permalink to &quot;品种&quot;">​</a></h4><p>展出郁金香品种100余个，30余万株。</p><h3 id="菊花展" tabindex="-1">菊花展 <a class="header-anchor" href="#菊花展" aria-label="Permalink to &quot;菊花展&quot;">​</a></h3><p>每年秋季举办菊花展，是北京著名的菊花观赏地。</p><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h3><p><strong>经典路线（约2-3小时）</strong>：</p><p>南门 → 保卫和平坊 → 社稷坛 → 拜殿 → 古柏 → 兰亭八柱亭 → 来今雨轩 → 郁金香花园 → 西门</p><p><strong>春季路线（看郁金香）</strong>：</p><p>南门 → 社稷坛 → 郁金香花园 → 古柏 → 保卫和平坊 → 东门</p><h3 id="交通方式" tabindex="-1">交通方式 <a class="header-anchor" href="#交通方式" aria-label="Permalink to &quot;交通方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方式</th><th style="text-align:left;">站点</th></tr></thead><tbody><tr><td style="text-align:left;">地铁</td><td style="text-align:left;">1号线天安门西站B口</td></tr><tr><td style="text-align:left;">公交</td><td style="text-align:left;">1路、52路、99路等天安门西站</td></tr><tr><td style="text-align:left;">步行</td><td style="text-align:left;">从故宫步行约10分钟</td></tr></tbody></table><h3 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h3><ol><li><strong>郁金香最佳时间</strong>：4月中下旬</li><li><strong>菊花最佳时间</strong>：10月中下旬</li><li><strong>人少时段</strong>：早上7:00前或下午4:00后</li><li><strong>结合游览</strong>：可与天安门广场、故宫一起游览</li><li><strong>门票便宜</strong>：门票仅3元</li><li><strong>古柏壮观</strong>：600年古柏值得一看</li></ol><h2 id="周边景点" tabindex="-1">周边景点 <a class="header-anchor" href="#周边景点" aria-label="Permalink to &quot;周边景点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">距离</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;">天安门广场</td><td style="text-align:center;">紧邻</td><td style="text-align:left;">世界最大城市广场</td></tr><tr><td style="text-align:left;">故宫</td><td style="text-align:center;">紧邻</td><td style="text-align:left;">明清皇宫</td></tr><tr><td style="text-align:left;">国家博物馆</td><td style="text-align:center;">紧邻</td><td style="text-align:left;">国家级博物馆</td></tr><tr><td style="text-align:left;">劳动人民文化宫</td><td style="text-align:center;">紧邻</td><td style="text-align:left;">太庙</td></tr></tbody></table><h2 id="文化价值" tabindex="-1">文化价值 <a class="header-anchor" href="#文化价值" aria-label="Permalink to &quot;文化价值&quot;">​</a></h2><p>中山公园是全国重点文物保护单位，是北京保存最完整的皇家祭祀建筑群。</p><p>社稷坛是中国古代&quot;左祖右社&quot;礼制的重要遗存，是研究中国古代礼制的重要实物资料。</p><hr><p><strong>📍 地址</strong>：北京市东城区中华路4号 <strong>📞 电话</strong>：010-66055431</p>',58)])])}const c=a(o,[["render",n]]);export{q as __pageData,c as default};
